SELECT spectral_data.freq_invcm, spectral_data.wavlen_um, datasets.description, datasets.location, datasets.collection_date
FROM spectral_data
JOIN datasets ON spectral_data.dataset_id = datasets.dataset_id;

SELECT freq_invcm, wavlen_um, data_quality_flag
FROM spectral_data
ORDER BY freq_invcm ASC;

WITH highest_radiance_datasets AS (
    SELECT dataset_id
    FROM spectral_data
    WHERE total_radiance_mum = (
        SELECT MAX(total_radiance_mum) FROM spectral_data
    )
),
accessing_researchers AS (
    SELECT researcher_id
    FROM data_access
    WHERE dataset_id IN (
        SELECT dataset_id FROM highest_radiance_datasets
    )
)
SELECT *
FROM researchers
WHERE researcher_id IN (
    SELECT researcher_id FROM accessing_researchers
);

SELECT freq_invcm, wavlen_um, path_thermal_cm, dataset_id 
FROM spectral_data 
WHERE path_thermal_cm = (SELECT MAX(path_thermal_cm) FROM spectral_data);

SELECT *
FROM spectral_data
WHERE freq_invcm > 3000;
